/**
 * Get poblados for a specific departamento + municipio
 */
export function getPoblados(departamento, municipio) {
  if (!departamento || !municipio) return []
  const dept = pobladosPorMunicipio[departamento]
  if (!dept) return []
  return dept[municipio] || []
}
